	private static Path estimatorPath(Path tempDir) throws Exception {
		Path estimatorPath = tempDir.resolve("join-estimator.rjes");
		Files.createDirectories(estimatorPath);
		Files.writeString(estimatorPath.resolve("metadata.bin"), "metadata");
		return estimatorPath;
	}

	private static Join join(String leftSubject, String sharedName, String rightObject) {
		return new Join(sp(leftSubject, P1, sharedName), sp(sharedName, P2, rightObject));
	}

	private static Join leftDeepThreeWayPath() {
		return new Join(new Join(sp("s", P1, "x"), sp("x", P2, "y")), sp("y", P3, "o"));
	}

	private static Join rightDeepThreeWayPath() {
		return new Join(sp("s", P1, "x"), new Join(sp("x", P2, "y"), sp("y", P3, "o")));
	}

	private static ArbitraryLengthPath alp(String subjectName, String objectName) {
		return new ArbitraryLengthPath(Var.of(subjectName), sp(subjectName, P1, objectName), Var.of(objectName), 1);
	}

	private static StatementPattern sp(String subjectName, IRI predicate, String objectName) {
		return new StatementPattern(Var.of(subjectName), Var.of("_p", predicate, true, true), Var.of(objectName));
	}

	private static void completeBinary(TupleExpr node, long actualRows, double plannedRows, double plannedWorkRows,
			long leftRows, long rightRows) {
		if (node instanceof org.eclipse.rdf4j.query.algebra.BinaryTupleOperator binary) {
			complete(binary.getLeftArg(), leftRows, leftRows, leftRows);
			complete(binary.getRightArg(), rightRows, rightRows, rightRows);
		}
		complete(node, actualRows, plannedRows, plannedWorkRows);
	}

	private static void complete(TupleExpr node, long actualRows, double plannedRows, double plannedWorkRows) {
		node.setRuntimeTelemetryEnabled(true);
		node.setResultSizeEstimate(plannedRows);
		node.setCostEstimate(plannedWorkRows);
		node.setDoubleMetricPlanned(TelemetryMetricNames.PLANNED_WORK_ROWS, plannedWorkRows);
		node.setResultSizeActual(actualRows);
		node.setLongMetricActual(TelemetryMetricNames.OUTPUT_ROWS_ACTUAL, actualRows);
		node.setLongMetricActual(TelemetryMetricNames.CLOSE_COUNT_ACTUAL, 1);
		node.setHasNextCallCountActual(actualRows + 1);
		node.setHasNextTrueCountActual(actualRows);
	}

	private static void completeWithoutTerminalFalse(TupleExpr node, long actualRows, double plannedRows,
			double plannedWorkRows) {
		complete(node, actualRows, plannedRows, plannedWorkRows);
		node.setHasNextCallCountActual(actualRows);
		node.setHasNextTrueCountActual(actualRows);
	}

	private static void completeCostFeedback(TupleExpr node, long actualRows, double plannedRows,
			double plannedWorkRows, double actualWorkRows) {
		node.setCostFeedbackTrackingEnabled(true);
		node.setCostFeedbackExpectedRows(plannedRows);
		node.setCostFeedbackExpectedWorkRows(plannedWorkRows);
		node.setCostFeedbackReportQErrorThreshold(LmdbOperatorFeedbackStats.DEFAULT_REPORT_Q_ERROR_THRESHOLD);
		node.setResultSizeEstimate(plannedRows);
		node.setCostEstimate(plannedWorkRows);
		node.setDoubleMetricPlanned(TelemetryMetricNames.PLANNED_WORK_ROWS, plannedWorkRows);
		node.setCostFeedbackActualRows(actualRows);
		node.setCostFeedbackActualWorkRows(actualWorkRows);
		node.setCostFeedbackCloseCountActual(1L);
		node.setCostFeedbackCompletedActual(true);
	}

	private static void completePathCostFeedback(ArbitraryLengthPath node, String endpointMode, long actualRows,
			double plannedRows, double plannedWorkRows, long candidateRows) {
		node.setStringMetricPlanned("plannedPropertyPathEndpointMode", endpointMode);
		node.setStringMetricPlanned("optimizer.pathEndpointMode", endpointMode);
		node.setCostFeedbackTrackingEnabled(true);
		node.setCostFeedbackExpectedRows(plannedRows);
		node.setCostFeedbackExpectedWorkRows(plannedWorkRows);
		node.setCostFeedbackReportQErrorThreshold(LmdbOperatorFeedbackStats.DEFAULT_REPORT_Q_ERROR_THRESHOLD);
		node.setResultSizeEstimate(plannedRows);
		node.setCostEstimate(plannedWorkRows);
		node.setDoubleMetricPlanned(TelemetryMetricNames.PLANNED_WORK_ROWS, plannedWorkRows);
		node.setCostFeedbackActualRows(actualRows);
		node.setLongMetricActual("optimizer.pathCandidateRowsActual", candidateRows);
		node.setCostFeedbackCloseCountActual(1L);
		node.setCostFeedbackCompletedActual(true);
	}

	private static double metric(LmdbOperatorFeedbackStats.OperatorEstimate estimate, String accessorName) {
		try {
			Method accessor = estimate.getClass().getMethod(accessorName);
			return ((Number) accessor.invoke(estimate)).doubleValue();
		} catch (NoSuchMethodException e) {
			fail("Operator feedback estimates must expose " + accessorName);
			return Double.NaN;
		} catch (ReflectiveOperationException e) {
			throw new AssertionError("Could not read " + accessorName, e);
		}
	}
